// Ref: #/components/schemas/FileType
type FileType string

const (
	FileTypeRegular   FileType = "regular"
	FileTypeDirectory FileType = "directory"
	FileTypeSymlink   FileType = "symlink"
	FileTypeBlock     FileType = "block"
	FileTypeChar      FileType = "char"
	FileTypeSocket    FileType = "socket"
	FileTypeFifo      FileType = "fifo"
)

// AllValues returns all FileType values.
func (FileType) AllValues() []FileType {
	return []FileType{
		FileTypeRegular,
		FileTypeDirectory,
		FileTypeSymlink,
		FileTypeBlock,
		FileTypeChar,
		FileTypeSocket,
		FileTypeFifo,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s FileType) MarshalText() ([]byte, error) {
	switch s {
	case FileTypeRegular:
		return []byte(s), nil
	case FileTypeDirectory:
		return []byte(s), nil
	case FileTypeSymlink:
		return []byte(s), nil
	case FileTypeBlock:
		return []byte(s), nil
	case FileTypeChar:
		return []byte(s), nil
	case FileTypeSocket:
		return []byte(s), nil
	case FileTypeFifo:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *FileType) UnmarshalText(data []byte) error {
	switch FileType(data) {
	case FileTypeRegular:
		*s = FileTypeRegular
		return nil
	case FileTypeDirectory:
		*s = FileTypeDirectory
		return nil
	case FileTypeSymlink:
		*s = FileTypeSymlink
		return nil
	case FileTypeBlock:
		*s = FileTypeBlock
		return nil
	case FileTypeChar:
		*s = FileTypeChar
		return nil
	case FileTypeSocket:
		*s = FileTypeSocket
		return nil
	case FileTypeFifo:
		*s = FileTypeFifo
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

